import{_ as n,H as t,f as i,i as a}from"./chunks/framework.DbTCwA-u.js";const m=JSON.parse('{"title":"Installation und Anforderungen","description":"Erfahren Sie, wie Sie EligiusNametag auf Ihrem Paper- oder Folia-Server installieren.","frontmatter":{"title":"Installation und Anforderungen","description":"Erfahren Sie, wie Sie EligiusNametag auf Ihrem Paper- oder Folia-Server installieren."},"headers":[],"relativePath":"de/installation.md","filePath":"de/installation.md"}'),r={name:"de/installation.md"};function l(s,e,o,d,g,u){return t(),i("div",null,[...e[0]||(e[0]=[a('<h1 id="installation-und-anforderungen" tabindex="-1">Installation und Anforderungen <a class="header-anchor" href="#installation-und-anforderungen" aria-label="Permalink to &quot;Installation und Anforderungen&quot;">​</a></h1><p>EligiusNametag ist ein modernes und leistungsstarkes Plugin. Da es die neuesten Funktionen der Minecraft Text-API und Multi-Threading nutzt, erfordert es eine aktuelle Umgebung.</p><h2 id="📋-systemanforderungen" tabindex="-1">📋 Systemanforderungen <a class="header-anchor" href="#📋-systemanforderungen" aria-label="Permalink to &quot;📋 Systemanforderungen&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Anforderung</th><th>Mindestversion</th><th>Grund</th></tr></thead><tbody><tr><td><strong>Plattform</strong></td><td>Paper 1.21 oder Folia 1.21+</td><td>Strikte Verwendung von <code>TEXT_DISPLAY</code> Komponenten und Brigadier-Befehlen.</td></tr><tr><td><strong>Java</strong></td><td>Java 21 LTS</td><td>Quellcode im JDK 21-Format kompiliert.</td></tr></tbody></table><h2 id="📦-abhangigkeiten" tabindex="-1">📦 Abhängigkeiten <a class="header-anchor" href="#📦-abhangigkeiten" aria-label="Permalink to &quot;📦 Abhängigkeiten&quot;">​</a></h2><p>Sie müssen die folgenden Plugins in Ihrem <code>plugins/</code> Ordner installiert haben:</p><ol><li><strong>ProtocolLib</strong> <em>(Erforderlich)</em>: Wird verwendet, um Hologrammpakete unsichtbar zu senden, ohne physische TPS zu verbrauchen.</li><li><strong>Vault</strong> <em>(Optional)</em>: Wenn Sie spezifische Nametag-Designs abhängig vom Rang des Benutzers (Admin, VIP usw.) vergeben möchten.</li><li><strong>PlaceholderAPI</strong> <em>(Optional)</em>: Um externe Variablen wie Statistiken, Geld oder Clans in den Nametags zu parsen.</li><li><strong>ItemsAdder</strong> <em>(Optional)</em>: Um benutzerdefinierte Emojis in Namen anzuzeigen.</li></ol><h2 id="🚀-installationsschritte" tabindex="-1">🚀 Installationsschritte <a class="header-anchor" href="#🚀-installationsschritte" aria-label="Permalink to &quot;🚀 Installationsschritte&quot;">​</a></h2><ol><li>Laden Sie die Datei <code>EligiusNametag-1.x.x.jar</code> aus dem <strong>Releases</strong> Tab herunter.</li><li>Kopieren Sie die Datei in das <code>plugins/</code> Verzeichnis Ihres Servers.</li><li>Stellen Sie sicher, dass <strong>ProtocolLib</strong> installiert ist.</li><li>Starten Sie Ihren Server.</li><li>Sie sehen die Startanimation in der Konsole mit der Eligius MC Katze, die bestätigt, dass sich das Plugin erfolgreich verbunden hat.</li><li>Fertig! Sie können alles in <code>plugins/EligiusNametag/</code> konfigurieren.</li></ol>',9)])])}const c=n(r,[["render",l]]);export{m as __pageData,c as default};
